import React, { useState } from 'react';
import { useAuth0 } from '@auth0/auth0-react';
import { useNavigate } from 'react-router-dom';
import { BarChart3, DollarSign, Users, ChevronDown } from 'lucide-react';
import './LandingPage.css';

/* ── Constants ─────────────────────────────────────────────────────────── */
const FEATURES = [
  {
    Icon: BarChart3,
    title: 'Workforce Analytics',
    description:
      'Real-time insights into team performance, headcount, and engagement metrics.',
  },
  {
    Icon: DollarSign,
    title: 'Payroll Automation',
    description:
      'Streamlined payroll processing with compliance built in from day one.',
  },
  {
    Icon: Users,
    title: 'Team Performance Tracking',
    description:
      'Continuous feedback loops and OKR tracking for high-performing teams.',
  },
];

/* ── Sub-components ─────────────────────────────────────────────────────── */

function LandingHeader() {
  const { loginWithRedirect, isAuthenticated } = useAuth0();
  const navigate = useNavigate();
  const [langOpen, setLangOpen] = useState(false);

  return (
    <header className="lp-header">
      <div className="lp-container">
        <div className="lp-header-inner">
          {/* Logo */}
          <span className="lp-logo">Chain</span>

          {/* Right side */}
          <nav className="lp-header-nav">
            {/* Language selector */}
            <div className="lp-lang-wrapper">
              <button
                className="lp-lang-btn"
                onClick={() => setLangOpen((p) => !p)}
                aria-haspopup="listbox"
                aria-expanded={langOpen}
              >
                <span>EN</span>
                <ChevronDown className="lp-lang-chevron" size={14} />
              </button>
            </div>

            {isAuthenticated ? (
              /* Already logged in → go to dashboard */
              <button
                className="lp-btn lp-btn-dark lp-btn-pill lp-btn-sm"
                onClick={() => navigate('/dashboard')}
              >
                Go to Dashboard
              </button>
            ) : (
              <>
                {/* Login */}
                <button
                  className="lp-link-btn"
                  onClick={() => loginWithRedirect()}
                >
                  Login
                </button>

                {/* Request Access */}
                <button
                  className="lp-btn lp-btn-dark lp-btn-pill lp-btn-sm"
                  onClick={() =>
                    loginWithRedirect({
                      authorizationParams: { screen_hint: 'signup' },
                    })
                  }
                >
                  Request Access
                </button>
              </>
            )}
          </nav>
        </div>
      </div>
    </header>
  );
}

function LandingHero() {
  const { loginWithRedirect } = useAuth0();

  return (
    <section className="lp-hero">
      <div className="lp-hero-glow" aria-hidden="true" />
      <div className="lp-container lp-hero-container">
        <div className="lp-hero-grid">
          {/* Left – copy */}
          <div className="lp-hero-copy">
            <h1 className="lp-hero-title">
              Operational Clarity for Modern Teams.
            </h1>
            <p className="lp-hero-subtitle">
              HR, payroll, compliance and performance management – unified.
            </p>

            <div className="lp-hero-ctas">
              <button
                className="lp-btn lp-btn-dark lp-btn-pill lp-btn-lg"
                onClick={() =>
                  loginWithRedirect({
                    authorizationParams: { screen_hint: 'signup' },
                  })
                }
              >
                Request a Demo
              </button>
              <button
                className="lp-btn lp-btn-outline lp-btn-pill lp-btn-lg"
                onClick={() => loginWithRedirect()}
              >
                Explore Platform
              </button>
            </div>
          </div>

          {/* Right – dashboard mockup */}
          <div className="lp-hero-image-wrap">
            <div className="lp-hero-image-card">
              <img
                src="https://images.unsplash.com/photo-1575388902449-6bca946ad549?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxtb2Rlcm4lMjBkYXNoYm9hcmQlMjBhbmFseXRpY3MlMjBpbnRlcmZhY2V8ZW58MXx8fHwxNzcxOTI3NjQ2fDA&ixlib=rb-4.1.0&q=80&w=1080"
                alt="Chain platform dashboard"
                className="lp-hero-img"
                onError={(e) => {
                  e.target.style.display = 'none';
                }}
              />
            </div>
            <div className="lp-hero-image-glow" aria-hidden="true" />
          </div>
        </div>
      </div>
    </section>
  );
}

function LandingFeatures() {
  return (
    <section className="lp-features">
      <div className="lp-container">
        <div className="lp-features-header">
          <h2 className="lp-features-title">Built for ambitious teams.</h2>
        </div>

        <div className="lp-features-grid">
          {FEATURES.map(({ Icon, title, description }) => (
            <div key={title} className="lp-feature-card">
              <div className="lp-feature-icon-wrap">
                <Icon size={24} />
              </div>
              <h3 className="lp-feature-card-title">{title}</h3>
              <p className="lp-feature-card-desc">{description}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

function LandingNewsletter() {
  const [email, setEmail] = useState('');

  const handleSubscribe = (e) => {
    e.preventDefault();
    // Newsletter logic can be wired here
  };

  return (
    <section className="lp-newsletter">
      <div className="lp-container lp-newsletter-container">
        <h2 className="lp-newsletter-title">Insights for Leaders</h2>
        <form className="lp-newsletter-form" onSubmit={handleSubscribe}>
          <input
            type="email"
            className="lp-email-input"
            placeholder="Enter your email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
          <button type="submit" className="lp-btn lp-btn-dark lp-btn-subscribe">
            Subscribe
          </button>
        </form>
      </div>
    </section>
  );
}

function LandingFooter() {
  return (
    <footer className="lp-footer">
      <div className="lp-container">
        <p className="lp-footer-text">
          © {new Date().getFullYear()} Chain. All rights reserved.
        </p>
      </div>
    </footer>
  );
}

/* ── Page ───────────────────────────────────────────────────────────────── */
export default function LandingPage() {
  return (
    <div className="lp-root">
      <LandingHeader />
      <main>
        <LandingHero />
        <LandingFeatures />
        <LandingNewsletter />
      </main>
      <LandingFooter />
    </div>
  );
}
